public class OverloadDemo {
    // Overloaded methods
    public int add(int a, int b) {
        return a + b;
    }

    public int add(int a, int b, int c) {
        return a + b + c;
    }

    public double add(double a, double b) {
        return a + b;
    }

    // Varargs
    public int sum(int... numbers) {
        int total = 0;
        for (int num : numbers) total += num;
        return total;
    }

    public static void main(String[] args) {
        OverloadDemo obj = new OverloadDemo();
        System.out.println("add(5,10): " + obj.add(5, 10));
        System.out.println("add(5,10,15): " + obj.add(5, 10, 15));
        System.out.println("add(5.5,10.5): " + obj.add(5.5, 10.5));
        System.out.println("sum(1,2,3,4,5): " + obj.sum(1, 2, 3, 4, 5));
    }
}

class Employee {
    String name;
    int id;
    double salary;

    // Default constructor
    Employee() {
        this.name = "Unknown";
        this.id = 0;
        this.salary = 0.0;
    }

    // Parameterized constructor
    Employee(String name) {
        this.name = name;
        this.id = 0;
        this.salary = 0.0;
    }

    Employee(String name, int id) {
        this.name = name;
        this.id = id;
        this.salary = 0.0;
    }

    Employee(String name, int id, double salary) {
        this.name = name;
        this.id = id;
        this.salary = salary;
    }

    void display() {
        System.out.println(name + ", ID: " + id + ", Salary: $" + salary);
    }
}

