class Person {
    String name;
    int age;

    Person(String name, int age) {
        this.name = name;  // Distinguishes instance variable
        this.age = age;
    }

    Person(String name) {
        this(name, 0);  // Calls another constructor
    }

    Person setAge(int age) {
        this.age = age;
        return this;  // Returns current object (method chaining)
    }

    void display() {
        System.out.println(name + ", " + age);
    }
}

public class ThisDemo {
    public static void main(String[] args) {
        Person p = new Person("John").setAge(25);
        p.display();
    }
}

public class VarargsDemo {
    // Varargs method
    public static int sum(int... numbers) {
        int total = 0;
        for (int num : numbers) {
            total += num;
        }
        return total;
    }

    // With other parameters
    public static void printValues(String message, int... values) {
        System.out.print(message + ": ");
        for (int val : values) {
            System.out.print(val + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("sum(1,2): " + sum(1, 2));
        System.out.println("sum(1,2,3,4,5): " + sum(1, 2, 3, 4, 5));
        System.out.println("sum(): " + sum());
        printValues("Numbers", 10, 20, 30);
    }
}

